function isPerc(r){return"string"==typeof r&&/^[0-9]+%$/.test(r)}function isPx(r){return"string"==typeof r&&/^[0-9]+px$/.test(r)}function toNum(r){if("number"==typeof r)return r;var t=r.match(/^([0-9]+)(px|%)$/);if(t)return parseInt(t[1],10);throw new Error("Could not match css value from "+r)}function toPx(r){return toNum(r)+"px"}function toCSS(r){return"number"!=typeof r&&isPerc(r)?r:toPx(r)}function percOf(r,t){return parseInt(r*toNum(t)/100,10)}function normalizeDimension(r,t){if("number"==typeof r)return r;if(isPerc(r))return percOf(t,r);if(isPx(r))return toNum(r);throw new Error("Can not normalize dimension: "+r)}export{isPerc,isPx,toNum,toPx,toCSS,percOf,normalizeDimension};